The strategy should be to merge the events into a completed (or cancelled) trip like: userId, cityStart, cityEnd, startTime, endTime. keep one for cancelled, one for booked. Then any query can be answered by iterating in either of the table.

not thread safe. Assumption : one user can book one ride at a time (since bookingId is not provided)
=================================
```java

 // intermediate DS to merge a full trip
 private Map<String, TreeSet<RideEvent>> userBookings = new HashMap<String, TreeSet<RideEvent>>();

// trip store to query. will contain a completed trip detail or cancelled one. The comparator may not be necessary - since we have to anyway apply lambda filter to get data
  // 2nd level of discussion could be how to make the querying more efficient
   private TreeSet<UserTrip> completions = new TreeSet<RideInfo.UserTrip>(new Comparator<RideInfo.UserTrip>() {

		@Override
		public int compare(UserTrip o1, UserTrip o2) {
			return Long.compare(o1.timeStart, o2.timeStart);
		}
	});
	private TreeSet<UserTrip> cancellations = new TreeSet<RideInfo.UserTrip>(new Comparator<RideInfo.UserTrip>() {

		@Override
		public int compare(UserTrip o1, UserTrip o2) {
			return Long.compare(o1.timeStart, o2.timeStart);
		}
	});

	// add events stream
	public void add(RideEvent event) {
		TreeSet<RideEvent> ub = userBookings.computeIfAbsent(event.userId, u -> new TreeSet<RideEvent>(new Comparator<RideEvent>() {

			@Override
			public int compare(RideEvent o1, RideEvent o2) {
				return Long.compare(o1.timestamp, o2.timestamp);
			}
		}));

       // if the current event is a `terminating` event, the previous lower timestamp `Booked` event is its start
        ub.add(event);
		if(event.event == Event.Cancelled || event.event == Event.Ended) {
			var opt = ub.stream().filter(e -> e.event == Event.Booked && e.timestamp < event.timestamp).sorted().findFirst();
			var start = opt.orElse(null);
			if(start != null) {
				ub.remove(start);
				ub.remove(event);

				if(event.event == Event.Ended) {
					completions.add(new UserTrip(event.userId, start.city, event.city, start.timestamp, event.timestamp));
				}
				else {
					cancellations.add(new UserTrip(event.userId, start.city, event.city, start.timestamp, event.timestamp));
				}
			}
		}				
}

